  /// Actualiza SOLO el campo 'codigo' en los documentos existentes.
  /// No toca ningún otro campo (deuda, saldo, etc.).
  static Future<String> actualizarCodigos() async {
    final db = FirebaseFirestore.instance;
    int total = 0;
    int errores = 0;
    const batchSize = 400;

    // Mapa de docId -> codigo extraido del array data
    final codigosMap = <String, String>{};
    for (final item in _codigosData) {
      codigosMap[item['id']!] = item['codigo']!;
    }

    WriteBatch batch = db.batch();
    int count = 0;

    for (final entry in codigosMap.entries) {
      final ref = db.collection(FirestoreCollections.locales).doc(entry.key);
      batch.update(ref, {
        'codigo': entry.value,
        'actualizadoEn': FieldValue.serverTimestamp(),
        'actualizadoPor': 'update_codigos_script',
      });
      count++;
      total++;

      if (count >= batchSize) {
        try {
          await batch.commit();
        } catch (e) {
          errores += count;
        }
        batch = db.batch();
        count = 0;
      }
    }

    if (count > 0) {
      try {
        await batch.commit();
      } catch (e) {
        errores += count;
      }
    }

    if (errores > 0) {
      return '⚠️ Actualización parcial: $total intentados, $errores con error.';
    }
    return '✅ Códigos actualizados exitosamente. Total: $total locales actualizados.';
  }

