  static Future<void> _ensureCatalogsExist(FirebaseFirestore db) async {
    final munId = 'MUN-choluteca';
    final merId = 'MER-MUN-choluteca-mercado-inmaculada-concepcion-de-choluteca';

    // 1. Asegurar Municipalidad
    final munRef = db.collection('municipalidades').doc(munId);
    final munDoc = await munRef.get();
    if (!munDoc.exists) {
      await munRef.set({
        'nombre': 'Choluteca',
        'activo': true,
        'creadoEn': FieldValue.serverTimestamp(),
      });
    }

    // 2. Asegurar Mercado
    final merRef = db.collection('mercados').doc(merId);
    final merDoc = await merRef.get();
    if (!merDoc.exists) {
      await merRef.set({
        'nombre': 'Mercado Inmaculada Concepcion de Choluteca',
        'nombreLower': 'mercado inmaculada concepcion de choluteca',
        'municipalidadId': munId,
        'activo': true,
        'creadoEn': FieldValue.serverTimestamp(),
        'ubicacion': 'Choluteca, Choluteca',
      });
    }
  }
